// The strategy is to find [Number][Name][Wage or next Number]
// Some wages are missing and replaced by the next ID.

preg_match_all('/(\d+)([A-Z\s\.\-\/]+)([\d\.]+)?/i', $raw, $matches, PREG_SET_ORDER);

$karyawan_wages = [];
foreach ($matches as $m) {
    $id = intval($m[1]);
    $name = trim($m[2]);
    $wage_raw = $m[3] ?? '';
    
    // If the "wage" is actually the next ID or very small, it might be 100.000 (starting with 1)
    $wage = floatval(str_replace('.', '', $wage_raw));
    
    // Manual adjustments for the "joined" ones
    if ($name == "HERI KRISTANTO") $wage = 0; // Missing in list text but maybe 100k
    if ($name == "IPI HARWANTO") $wage = 0;
    if ($name == "AKBAR") $wage = 0;
    if ($name == "ZAINUDIN") $wage = 0;
    
    if ($wage > 0) {
        $karyawan_wages[$name] = $wage;
    }
}

// Add Upah Column
echo "Adding upah column...\n";
$koneksi->query("ALTER TABLE ms_karyawan ADD COLUMN upah DOUBLE DEFAULT 0 AFTER id_golongan");

// Update Wages
echo "Updating employee wages...\n";
foreach ($karyawan_wages as $name => $wage) {
    $name_esc = $koneksi->real_escape_string($name);
    $koneksi->query("UPDATE ms_karyawan SET upah = '$wage' WHERE nama_karyawan LIKE '$name_esc%'");
}

echo "Migration finished. Please check ms_karyawan table.\n";
